    pub depended_on_by: BTreeSet<AgentId>,
}

impl AgentSession {
    pub fn new(launch: AgentLaunch) -> Self {
        Self {
            id: launch.id,
            kind: launch.kind,

            kind: launch.kind,
            feature: launch.feature,
            state: AgentState::Running,
            messages: vec![ChatMessage::new(MessageRole::User, launch.prompt)],
