fn open_selected_new_window(&mut self) -> Vec<UiAction> {
    let Some(agent_id) = self.action_agent_id() else {
        return Vec::new();
    };
    self.windows.push(UiWindow::chat(agent_id.clone()));
    self.active_window = self.windows.len() - 1;
