        self.select_command_interface();
        self.focus = PaneFocus::Left;
        return;
    }
    if let Some(agent_id) = self.control_selected_agent_id() {
        let _ = self.select_agent(&agent_id);
        self.focus = PaneFocus::Left;
    }
}

