fn apply_controller_events(&mut self) {
    let events = self.controller.drain_events();
    if events.is_empty() {
        return;
    }
    for event in events {
        match event {
            WorkLeafEvent::AgentAdded { session } | WorkLeafEvent::AgentUpdated { session } => {
                self.upsert_cached_session(session.clone());
                self.apply_session_to_ui(&session);
            }
            WorkLeafEvent::AgentStatusUpdated {
                agent_id,
                kind,
                title,
                feature,
                loading,
            } => {
                let session =
                    self.upsert_cached_session_status(agent_id, kind, title, feature, loading);
                self.apply_session_to_ui(&session);
            }
            WorkLeafEvent::AgentLineAppended { agent_id, line } => {
                self.append_cached_agent_line(&agent_id, line);

        agent_id: &AgentId,
        prompt: &str,
    ) -> Result<CodexInvocation, AgentError> {
        let (has_session, feature, resume_id) = {
            let state = self
                .state
                .lock()
                .expect("codex backend state mutex poisoned");
            let feature = state
                .sessions
                .get(agent_id)
                .map(|session| session.feature.clone())
                .unwrap_or_else(|| "unknown".to_string());
            let has_session = state.sessions.contains_key(agent_id);
            let resume_id = state
                .thread_ids
                .get(agent_id)
                .cloned()
                .unwrap_or_else(|| agent_id.as_str().to_string());
            (has_session, feature, resume_id)
        };
        let stdin = if has_session {
            prompt.to_string()
        } else {
            self.policy.inject(agent_id, &feature, prompt)
        };
        self.resume_invocation(&resume_id, stdin)
    }

    pub fn record_launch_reply(
        &mut self,
        request: AgentLaunch,
        reply: String,
    ) -> Result<AgentSession, AgentError> {
        let mut session = AgentSession::new(request);
        session.push_message(MessageRole::Agent, reply);
        self.state
            .lock()
            .expect("codex backend state mutex poisoned")
            .sessions
            .insert(session.id.clone(), session.clone());
        Ok(session)
    }

    pub fn record_launch_output(
        &mut self,
        request: AgentLaunch,
        output: String,
    ) -> Result<AgentSession, AgentError> {
        let parsed = parse_codex_output(&output);
        if let Some(thread_id) = parsed.thread_id {
            self.state
                .lock()
                .expect("codex backend state mutex poisoned")
                .thread_ids
                .insert(request.id.clone(), thread_id);
        }
        self.record_launch_reply(request, parsed.agent_reply.unwrap_or(output))
    }

    pub fn session(&self, agent_id: &AgentId) -> Option<AgentSession> {
        self.state
            .lock()
            .expect("codex backend state mutex poisoned")
            .sessions
            .get(agent_id)
            .cloned()
    }

    fn run_backend_command(
        &mut self,
        agent_id: &AgentId,
        command: &str,
        arguments: &str,
    ) -> Result<String, AgentError> {
        let mut state = self
            .state
            .lock()
            .expect("codex backend state mutex poisoned");
        if !state.sessions.contains_key(agent_id) {
            return Err(AgentError::UnknownSession(agent_id.clone()));
        }

        let output = match command {
            "status" => render_codex_status(&state, agent_id),
            "fork" => render_codex_fork(&state, agent_id, arguments),
            other => format!("backend command /{other} is not supported by Codex"),
        };
        let command_line = render_backend_command_line(command, arguments);
        let session = state
            .sessions
            .get_mut(agent_id)
            .ok_or_else(|| AgentError::UnknownSession(agent_id.clone()))?;
        session.push_message(MessageRole::User, command_line);
        session.push_message(MessageRole::Agent, output.clone());
        Ok(output)
    }

    fn exec_invocation(&self, stdin: String) -> CodexInvocation {
        let mut args = vec![
            "--cd".to_string(),
            self.config.project_dir.display().to_string(),
            "--sandbox".to_string(),
            self.config.sandbox.as_codex_arg().to_string(),
            "--ask-for-approval".to_string(),
            "never".to_string(),
        ];
        if let Some(model) = &self.config.model {
            args.push("--model".to_string());
            args.push(model.clone());
        }
        args.push("exec".to_string());
        args.push("--color".to_string());
        args.push("never".to_string());
        args.push("--json".to_string());
        args.push("-".to_string());
        CodexInvocation {
            program: self.config.binary.clone(),
            args,
            stdin,
        }
    }

    fn resume_invocation(
        &self,
        resume_id: &str,
        stdin: String,
    ) -> Result<CodexInvocation, AgentError> {
        let mut args = vec![
            "--cd".to_string(),
            self.config.project_dir.display().to_string(),
            "--sandbox".to_string(),
            self.config.sandbox.as_codex_arg().to_string(),
            "--ask-for-approval".to_string(),
            "never".to_string(),
        ];
        if let Some(model) = &self.config.model {
            args.push("--model".to_string());
            args.push(model.clone());
        }
        args.extend([
            "exec".to_string(),
            "resume".to_string(),
            "--json".to_string(),
            resume_id.to_string(),
            "-".to_string(),
        ]);
        Ok(CodexInvocation {
            program: self.config.binary.clone(),
            args,
            stdin,
        })
    }

    fn run_invocation_streaming(
        &self,
        invocation: &CodexInvocation,
        agent_id: Option<&AgentId>,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<String, AgentError> {
        let mut command = Command::new(&invocation.program);
        command
            .args(&invocation.args)
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped());
        configure_agent_child_process(&mut command);
        let mut child = command.spawn()?;
        let child_pid = child.id();
        let _process_guard = self.shutdown.register(child.id());
        if let Some(agent_id) = agent_id {
            self.state
                .lock()
                .expect("codex backend state mutex poisoned")
                .active_processes
                .insert(agent_id.clone(), child_pid);
        }

        if let Some(stdin) = child.stdin.as_mut() {
            stdin.write_all(invocation.stdin.as_bytes())?;
        }
        drop(child.stdin.take());

        let stderr_reader = child.stderr.take().map(|mut stderr| {
            thread::spawn(move || {
                let mut text = String::new();
                let _ = stderr.read_to_string(&mut text);
                text
            })
        });

        let mut stdout_text = String::new();
        if let Some(stdout) = child.stdout.take() {
            for line in BufReader::new(stdout).lines() {
                let line = line?;
                if let Some(event) = codex_stream_event(&line) {
                    sink(event);
                }
                stdout_text.push_str(&line);
                stdout_text.push('\n');
            }
        }

        let status = child.wait()?;
        if let Some(agent_id) = agent_id {
            let mut state = self
                .state
                .lock()
                .expect("codex backend state mutex poisoned");
            if state
                .active_processes
                .get(agent_id)
                .is_some_and(|pid| *pid == child_pid)
            {
                state.active_processes.remove(agent_id);
            }
        }
        let stderr = stderr_reader
            .and_then(|reader| reader.join().ok())
            .unwrap_or_default();

        if status.success() {
            Ok(stdout_text.trim().to_string())
        } else {
            Err(AgentError::ProcessFailed {
                program: invocation.program.clone(),
                status: status.code(),
                stderr: process_failure_output(stderr, &stdout_text),
            })
        }
    }
}

impl Drop for CodexBackend {
    fn drop(&mut self) {
        if Arc::strong_count(&self.lifecycle) == 1 {
            self.shutdown.shutdown();
        }
    }
}

impl AgentBackend for CodexBackend {
    fn launch(&mut self, request: AgentLaunch) -> Result<AgentSession, AgentError> {
        let invocation = self.build_launch_invocation(&request);
        let output = self.run_invocation_streaming(&invocation, Some(&request.id), &mut |_| {})?;
        self.record_launch_output(request, output)
    }

    fn send(&mut self, agent_id: &AgentId, prompt: &str) -> Result<ChatMessage, AgentError> {
        let invocation = self.build_send_invocation(agent_id, prompt)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), &mut |_| {})?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        let mut state = self
            .state
            .lock()
            .expect("codex backend state mutex poisoned");
        if let Some(session) = state.sessions.get_mut(agent_id) {
            session.push_message(MessageRole::User, prompt);
        } else {
            state.sessions.insert(
                agent_id.clone(),
                AgentSession::new(AgentLaunch::new(
                    agent_id.clone(),
                    AgentKind::Codex,
                    "unknown",
                    prompt,
                )),
            );
        }
        let session = state
            .sessions
            .get_mut(agent_id)
            .ok_or_else(|| AgentError::UnknownSession(agent_id.clone()))?;
        session.messages.push(message.clone());
        Ok(message)
    }

    fn command(
        &mut self,
        agent_id: &AgentId,
        command: &str,
        arguments: &str,
    ) -> Result<ChatMessage, AgentError> {
        let output = self.run_backend_command(agent_id, command, arguments)?;
        Ok(ChatMessage::new(MessageRole::Agent, output))
    }

    fn shutdown_handle(&self) -> AgentShutdownHandle {
        self.shutdown.clone()
    }

    fn interrupt(&mut self, agent_id: &AgentId) -> Result<(), AgentError> {
        let pid = self
            .state
            .lock()
            .expect("codex backend state mutex poisoned")
            .active_processes
            .get(agent_id)
            .copied();
        if let Some(pid) = pid {
            let _ = self.shutdown.terminate_process(pid);
        }
        Ok(())
    }

    fn launch_streaming(
        &mut self,
        request: AgentLaunch,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<AgentSession, AgentError> {
        let invocation = self.build_launch_invocation(&request);
        let output = self.run_invocation_streaming(&invocation, Some(&request.id), sink)?;
        self.record_launch_output(request, output)
    }

    fn send_streaming(
        &mut self,
        agent_id: &AgentId,
        prompt: &str,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<ChatMessage, AgentError> {
        let invocation = self.build_send_invocation(agent_id, prompt)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), sink)?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        let mut state = self
            .state
            .lock()
            .expect("codex backend state mutex poisoned");
        if let Some(session) = state.sessions.get_mut(agent_id) {
            session.push_message(MessageRole::User, prompt);
        } else {
            state.sessions.insert(
                agent_id.clone(),
                AgentSession::new(AgentLaunch::new(
                    agent_id.clone(),
                    AgentKind::Codex,
                    "unknown",
                    prompt,
                )),
            );
        }
        let session = state
            .sessions
            .get_mut(agent_id)
            .ok_or_else(|| AgentError::UnknownSession(agent_id.clone()))?;
        session.messages.push(message.clone());
        Ok(message)
    }
}

fn render_backend_command_line(command: &str, arguments: &str) -> String {
    if arguments.trim().is_empty() {
        format!("/{command}")
    } else {
        format!("/{command} {}", arguments.trim())
    }
}

