+    let thread_id = state
+        .thread_ids
+        .get(agent_id)
+        .map(String::as_str)
+        .unwrap_or_else(|| agent_id.as_str());
+    let runtime_state = if state.active_processes.contains_key(agent_id) {
+        "active"
+    } else {
+        "idle"
+    };
+    format!(
+        "Codex session status\nagent: {agent_id}\nthread: {thread_id}\nfeature: {}\nstate: {runtime_state}\nmessages: {}",
+        session.feature,
+        session.messages.len()
+    )
+}
+
+fn render_codex_fork(state: &CodexBackendState, agent_id: &AgentId, arguments: &str) -> String {
+    let thread_id = state
+        .thread_ids
+        .get(agent_id)
+        .map(String::as_str)
+        .unwrap_or_else(|| agent_id.as_str());
+    let prompt = arguments.trim();
+    if prompt.is_empty() {
+        format!("Codex fork requested\nsource thread: {thread_id}")
+    } else {
+        format!("Codex fork requested\nsource thread: {thread_id}\nprompt: {prompt}")
+    }
+}
